// Parse and filter Frigate events with smart priority + cooldown dedup
const body = $input.item.json.body || $input.item.json;

// CRITICAL: Only process 'end' events for one notification per detection
const eventType = body.type;
if (eventType !== 'end') {
  return [];
}

const event = body.after || body;
const date = new Date();
const hour = date.getHours();
const nowMs = date.getTime();
const formattedTime = date.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });
const formattedDate = date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });

const isDaytime = hour >= 7 && hour < 22;
const isNight = !isDaytime;

const eventId = event.id;
const camera = event.camera;
const object = event.label;
const score = event.top_score || 0;

const cameraNames = {
  'cobra_cam_1': 'Front Door',
  'cobra_cam_2': 'Driveway',
  'cobra_cam_3': 'Backyard',
  'cobra_cam_4': 'Carport'
};
const cameraName = cameraNames[camera] || camera;

// --- Hard filters ---
if (score < 0.6) return [];
if (['plant', 'tree'].includes(object)) return [];

// Drop daytime cars entirely — never interesting
if (object === 'car' && isDaytime) return [];

// Higher confidence threshold for non-person objects
if (object !== 'person' && score < 0.85) return [];

// --- Cooldown dedup (per camera+object) ---
const staticData = $getWorkflowStaticData('global');
if (!staticData.cooldowns) staticData.cooldowns = {};

// Purge stale entries older than 1 hour
for (const key of Object.keys(staticData.cooldowns)) {
  if (nowMs - staticData.cooldowns[key] > 3600000) {
    delete staticData.cooldowns[key];
  }
}

const cooldownKey = `${camera}:${object}`;
const cooldownMs = object === 'person' ? 120000 : 300000; // 2min person, 5min other

if (staticData.cooldowns[cooldownKey] && (nowMs - staticData.cooldowns[cooldownKey]) < cooldownMs) {
  return []; // Still in cooldown — suppress
}
staticData.cooldowns[cooldownKey] = nowMs;

// --- Priority assignment ---
let priority = 2;
let isPerson = false;

if (object === 'person') {
  isPerson = true;
  priority = isNight ? 5 : 4;
} else if (object === 'car' && isNight && camera === 'cobra_cam_3') {
  isPerson = true;
  priority = 5;
} else {
  priority = 2;
}

return [
  {
    json: {
      eventId,
      camera,
      cameraName,
      object,
      score,
      priority,
      isPerson,
      isNight,
      formattedTime,
      formattedDate,
      timestamp: date.toISOString()
    }
  }
];

